SELECT r.id, r.role_name, r.remark, r.role_state, r.create_time, r.update_time, r.data_flag FROM sys_role r
AND r.id != 'ordinary_user'
AND r.role_name LIKE CONCAT('%', #{query.roleName}, '%')
AND r.role_state = #{query.roleState}
AND r.create_time BETWEEN #{query.startTime} AND #{query.endTime}
